int main() {
    char line[512], clean[512];
    fgets(line, sizeof(line), stdin);
    int j = 0;
    for (int i = 0; line[i]; i++)
        if (isalnum((unsigned char)line[i]))
            clean[j++] = tolower((unsigned char)line[i]);
    clean[j] = '\0';
    int ok = 1;
